UPDATE block SET config = '{"contentKey": "story", "heading": "Story", "body": "Dannis Seay and Naomi Nguyen''s story began at Toast & Berry, unfolding like a scene from a romantic comedy. Naomi arrived at the wrong location, leaving Dannis waiting for an entire hour. Yet, when she finally arrived, he couldn''t take his eyes off her. Naomi was immediately charmed by his warm smile, kind eyes, and effortless conversation, along with his gentlemanly manners.\n\nThrough it all, it''s the everyday moments that inspire the most: Dannis caring for Naomi and their pets, Naomi''s kindness, and their shared laughter. Together, they''ve built a life founded on love, curiosity, and adventure."}', updatedAt = 1775819943575 WHERE id = 'blk_dn_s4';
UPDATE block SET config = '{"contentKey": "registry", "heading": "Registry", "body": "Your presence is enough of a present to us! But for those of you who are stubborn, we''ve put together a wish-list to help you out."}', updatedAt = 1775819943575 WHERE id = 'blk_dn_rg4';
UPDATE block SET config = '{"contentKey": "travel", "heading": "Travel", "body": "A Vietnam eVisa is required for most international visitors. Apply for a single-entry eVisa before your trip at the official Vietnam government portal. Fly into Tan Son Nhat International Airport (SGN) in Ho Chi Minh City."}', updatedAt = 1775819943575 WHERE id = 'blk_dn_t4';
UPDATE block SET config = '{"contentKey": "accommodations", "heading": "Where to Stay", "body": "We are thrilled to share our wedding day with all of you! We understand that traveling can be a significant commitment, so we are pleased to offer everyone a complimentary stay at the resort on the night of the wedding. If you''re coming from a distance, we recommend arriving a day early to relax and settle in before the festivities begin."}', updatedAt = 1775819943575 WHERE id = 'blk_dn_a4';
